// Minimal markdown renderer fallback (air-gap safe)
(function(){
  if(typeof window.marked!=='undefined')return;
  window.marked={parse:function(md){
    if(!md)return'';
    var h=md.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    h=h.replace(/^### (.+)$/gm,'<h3>$1</h3>');
    h=h.replace(/^## (.+)$/gm,'<h2>$1</h2>');
    h=h.replace(/^# (.+)$/gm,'<h1>$1</h1>');
    h=h.replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>');
    h=h.replace(/`([^`]+)`/g,'<code>$1</code>');
    h=h.replace(/^\|(.+)\|$/gm,function(m,c){return'<tr>'+c.split('|').map(function(cell){return'<td>'+cell.trim()+'</td>';}).join('')+'</tr>';});
    h=h.replace(/\n\n/g,'</p><p>');
    return'<div class="markdown-body"><p>'+h+'</p></div>';
  }};
})();
